SELECT job_role_name
FROM job_roles
WHERE job_role_id = 0;

SELECT job_role_name
FROM job_roles
WHERE job_role_id < 2;

SELECT salary_range, percentage, difference_with_previous_year
FROM salaries
ORDER BY percentage DESC;

SELECT MAX(percentage) AS max_percentage_2019
FROM salary_trends
WHERE year = 2019;

SELECT salary_range, count
FROM salaries
ORDER BY count DESC;
